const email = $input.first().json;

const sender = email.from?.emailAddress?.address || email.from || 'onbekend';
const senderName = email.from?.emailAddress?.name || sender.split('@')[0] || 'Klant';
const subject = email.subject || '(geen onderwerp)';
const body = email.body?.content || email.bodyPreview || '';

// Strip HTML tags
const bodyText = body.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

// Filter: sla puur automatische systeem-mails over (alleen op afzender, nooit op onderwerp)
const autoSenders = ['noreply', 'no-reply', 'mailer-daemon', 'postmaster', 'donotreply', 'do-not-reply', '@shopify.com', '@klaviyo.com', '@mailchimp.com', '@notifications.', 'notifications@'];
const senderLower = sender.toLowerCase();
const isAuto = autoSenders.some(s => senderLower.includes(s));

if (isAuto) return [];

// Build Airtable formula for duplicate check (zelfde afzender, laatste 24u, nog open)
const formula = `AND({Afzender} = "${sender.replace(/"/g, '')}", IS_AFTER({Datum}, DATEADD(NOW(), -24, 'hours')), OR({Status} = "Nieuw", {Status} = "In behandeling"))`;

return [{
  json: {
    sender,
    senderName,
    subject,
    bodyText,
    duplicateFormula: formula
  }
}];

let orders = [];
try {
  const data = $input.first().json;
  orders = data.orders || [];
} catch(e) {
  orders = [];
}

if (orders.length === 0) {
  return [{ json: { hasOrder: false, orderInfo: 'Geen order gevonden voor dit e-mailadres.' } }];
}

const o = orders[0];
const orderNumber = o.name || 'onbekend';
const orderDate = o.created_at ? new Date(o.created_at).toLocaleDateString('nl-NL') : 'onbekend';
const financialStatus = o.financial_status === 'paid' ? 'Betaald' : (o.financial_status || 'onbekend');

const statusMap = { fulfilled: 'Verstuurd', partial: 'Gedeeltelijk verstuurd', unfulfilled: 'Nog niet verstuurd', restocked: 'Teruggestuurd' };
const fulfillmentStatusNL = statusMap[o.fulfillment_status] || 'Nog niet verstuurd';

const products = (o.line_items || []).map(i => i.title + (i.variant_title && i.variant_title !== 'Default Title' ? ' (' + i.variant_title + ')' : '')).join(', ');

let trackingNumber = '';
let trackingUrl = '';
let carrier = '';
let shippedDate = '';

if (o.fulfillments && o.fulfillments.length > 0) {
  const f = o.fulfillments[0];
  trackingNumber = f.tracking_number || '';
  trackingUrl = f.tracking_url || '';
  carrier = f.tracking_company || '';
  shippedDate = f.created_at ? new Date(f.created_at).toLocaleDateString('nl-NL') : '';
}

let orderInfo = `Order: ${orderNumber} (geplaatst op ${orderDate})\nProducten: ${products}\nBetaalstatus: ${financialStatus}\nVerzendstatus: ${fulfillmentStatusNL}`;
if (shippedDate) orderInfo += ` (verstuurd op ${shippedDate})`;
if (carrier) orderInfo += `\nVervoerder: ${carrier}`;
if (trackingNumber) orderInfo += `\nTrackingnummer: ${trackingNumber}`;
if (trackingUrl) orderInfo += `\nTracking link: ${trackingUrl}`;

return [{ json: { hasOrder: true, orderInfo, orderNumber, fulfillmentStatusNL, trackingUrl, trackingNumber, carrier } }];

const claudeResponse = $input.first().json;
const text = claudeResponse.content[0].text;

const emailData = $('✍️ Bouw Prompt').first().json;

// Parse intent
const intentMatch = text.match(/INTENT:\s*([^\n]+)/);
const intent = intentMatch ? intentMatch[1].trim() : 'general_question';

// Parse sentiment
const sentimentMatch = text.match(/SENTIMENT:\s*([^\n]+)/);
const sentiment = sentimentMatch ? sentimentMatch[1].trim() : 'neutral';

// Parse risk
const riskMatch = text.match(/RISK:\s*([^\n]+)/);
const risk = riskMatch ? riskMatch[1].trim() : 'low';

// Parse urgentie
const urgencyMatch = text.match(/URGENTIE:\s*([^\n]+)/);
const urgency = urgencyMatch ? urgencyMatch[1].trim() : 'NORMAAL';
const isUrgent = urgency === 'URGENT' || risk === 'high';

// Parse reden urgentie
const reasonMatch = text.match(/REDEN_URGENTIE:\s*([^\n]+)/);
const urgencyReason = reasonMatch ? reasonMatch[1].trim() : 'n.v.t.';

// Parse 2+1 variant en akkoord
const variantMatch = text.match(/VARIANT:\s*([^\n]+)/);
const akkoordMatch = text.match(/KLANT_AKKOORD:\s*([^\n]+)/);
const rawVariant = variantMatch ? variantMatch[1].trim().toLowerCase().replace(/\s+/g, '').replace(/-/g, '') : 'onbekend';
const klantAkkoord = akkoordMatch ? akkoordMatch[1].trim().toLowerCase() : 'onbekend';
const is2plus1Confirmation = (intent === 'order_2plus1_confirmation') && (klantAkkoord === 'ja');
const variantLabels = { naturel: 'Naturel', reguliervanille: 'Regulier \u2014 Vanille', reguliersinaasappel: 'Regulier \u2014 Sinaasappel', vitaminee: 'Vitamine E', vitamine_e: 'Vitamine E' };
const betaalverzoekVariant = rawVariant;
const variantLabel = variantLabels[rawVariant] || rawVariant;

// Parse concept (alles na CONCEPT:)
const draftMatch = text.match(/CONCEPT:[\s\S]*?(Hi [\s\S]+)/);
const draft = draftMatch ? draftMatch[1].trim() : text;

// Bouw Telegram berichten (hier in Code node, niet in expressie)
const cleanDraft = String(draft).replace(/</g, '&lt;').replace(/>/g, '&gt;').substring(0, 3000);

let telegramMsgNormaal = '\uD83D\uDFE1 <b>NIEUW CONCEPT \u2014 ' + intent.toUpperCase() + '</b>\n\n\uD83D\uDC64 <b>Van:</b> ' + emailData.senderName + ' (' + emailData.sender + ')\n\uD83D\uDCCB <b>Onderwerp:</b> ' + emailData.subject + '\n\n\u2015\u2015\u2015\u2015\u2015\u2015\n\uD83D\uDCDD <b>CONCEPT:</b>\n\n' + cleanDraft + '\n\u2015\u2015\u2015\u2015\u2015\u2015\n\n\u2705 Controleer en stuur door naar klant als het klopt.';

const telegramMsgUrgent = '\uD83D\uDD34 <b>URGENT \u2014 ' + intent.toUpperCase() + '</b>\n\n\uD83D\uDC64 <b>Van:</b> ' + emailData.senderName + ' (' + emailData.sender + ')\n\uD83D\uDCCB <b>Onderwerp:</b> ' + emailData.subject + '\n\u26A0\uFE0F <b>Reden:</b> ' + urgencyReason + '\n\n\u2015\u2015\u2015\u2015\u2015\u2015\n\uD83D\uDCDD <b>CONCEPT:</b>\n\n' + cleanDraft + '\n\u2015\u2015\u2015\u2015\u2015\u2015\n\n\u2705 Controleer en stuur door naar klant als het klopt.';

// Override message voor 2+1 bevestiging
if (is2plus1Confirmation) {
  telegramMsgNormaal = '\u2705 <b>2+1 BEVESTIGING \u2014 KLANT AKKOORD</b>\n\n\uD83D\uDC64 <b>Van:</b> ' + emailData.senderName + ' (' + emailData.sender + ')\n\uD83E\uDDF4 <b>Variant:</b> ' + variantLabel + '\n\uD83D\uDCB0 <b>Bedrag:</b> \u20AC4,95\n\n\u2015\u2015\u2015\u2015\u2015\u2015\n\uD83D\uDCDD <b>KLANT ANTWOORD:</b>\n\n' + cleanDraft + '\n\u2015\u2015\u2015\u2015\u2015\u2015\n\n\uD83D\uDCB3 Klik \"Betaalverzoek + Picqer\" om alles automatisch te starten.';
}

return [{
  json: {
    category: intent,
    sentiment,
    risk,
    urgency: isUrgent ? 'Hoog' : 'Normaal',
    isUrgent,
    urgencyReason,
    draft,
    sender: emailData.sender,
    senderName: emailData.senderName,
    subject: emailData.subject,
    bodyText: emailData.bodyText,
    telegramMsgNormaal,
    telegramMsgUrgent,
    betaalverzoekVariant,
    variantLabel,
    klantAkkoord,
    is2plus1Confirmation
  }
}];

const verwerk = $('📝 Verwerk Antwoord').first().json;
const recordId = $input.first().json.id;

let replyMarkupObj;
if (verwerk.is2plus1Confirmation && verwerk.betaalverzoekVariant && verwerk.betaalverzoekVariant !== 'onbekend') {
  replyMarkupObj = {
    inline_keyboard: [[
      { text: '\u2705 Verstuur bevestiging', callback_data: 'send_' + recordId },
      { text: '\uD83D\uDCB3 Betaalverzoek + Picqer (' + verwerk.variantLabel + ')', callback_data: 'shopify_' + verwerk.betaalverzoekVariant + '_' + recordId }
    ]]
  };
} else {
  replyMarkupObj = {
    inline_keyboard: [[
      { text: '\u2705 Verstuur naar klant', callback_data: 'send_' + recordId },
      { text: '\u270F\uFE0F Aanpassen', callback_data: 'edit_' + recordId },
      { text: '\uD83D\uDCB3 Betaalverzoek', callback_data: 'payment_' + recordId }
    ]]
  };
}

return [{ json: { replyMarkup: JSON.stringify(replyMarkupObj), is2plus1Confirmation: verwerk.is2plus1Confirmation, variantLabel: verwerk.variantLabel } }];
